$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_7c590d9272ad1786e0e73357bf415267'] = 'Tämä ilmainen GitHub-moduuli toimitetaan ilman yksilöllistä teknistä tukea. Asennus, määritys, tuotantotestaus, päivitykset ja vianmääritys ovat saatavilla Joobox PrestaShop Cloud -asiakkaille tai muun JOO INTERNET MEDIA LTD:n kanssa erikseen sovitun maksullisen palvelun asiakkaille.';
