$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bafd7322c6e97d25b6299b5d6fe8920b'] = 'Ei';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_83112255bb4233cad4276eab160483e8'] = 'Kytkee puhdistimen päälle tai pois. Kun se on pois käytöstä, cron-URL ja manuaalinen käynnistyspainike eivät poista vanhoja tilastoja. Käytä tätä, kun haluat pitää moduulin asennettuna mutta pysäyttää puhdistuksen tilapäisesti.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_896e1fd6ab19d8bbd2f58f989fbaac76'] = 'Yhteystilastojen säilytyspäivät';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_b878a67f82524d412dae79ad597ff402'] = 'Tätä vanhemmat rivit poistetaan tauluista connections, connections_source ja connections_page.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Anna päivien määrä, jonka ajan raakoja PrestaShop-kävijätilastoja säilytetään. Esimerkki: 60 tarkoittaa, että moduuli säilyttää viimeiset 60 päivää ja poistaa vanhemmat tietueet tauluista ps_connections, ps_connections_source ja ps_connections_page. Älä aseta arvoksi 1, ellet ole varma, ettet tarvitse tuoreita kävijätilastoja.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_1300769d8d72fc8218b40772f1c25efc'] = 'Eräkoko';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Yhdessä erässä käsiteltävien yhteyksien enimmäismäärä.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Anna kuinka monta pääyhteystietuetta voidaan käsitellä yhdessä sisäisessä erässä. Pienemmät arvot ovat turvallisempia heikolla hostingilla mutta vaativat enemmän cron-ajoja. Suuremmat arvot puhdistavat nopeammin mutta voivat pitää tietokantalukkoja pidempään. Suositeltu aloitusarvo: 1000–5000; nosta vasta ajoajan testaamisen jälkeen.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Enimmäiserät ajoa kohti';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Rajoittaa yhden cron-ajon tekemän työn määrää.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Anna kuinka monta erää voidaan suorittaa yhden cron-ajon aikana. Mahdollinen poistettujen pääyhteystietueiden määrä on noin Eräkoko kerrottuna Enimmäiserät ajoa kohti. Esimerkki: 5000 ja 10 tarkoittaa enintään noin 50000 tietuetta yhdessä cron-ajossa. Laske arvoa, jos kauppa hidastuu puhdistuksen aikana.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a1a47524ffa9c839887703df1fbe70a3'] = 'Tyhjennä ps_layered_filter_block';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_924684322fe68e56ef9205e7f480f598'] = 'Tyhjentää faceted/layered-haun lohkovälimuistin TRUNCATE TABLE -komennolla. MySQL/MariaDB luo taulun uudelleen tyhjänä.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Ota käyttöön vain, jos ps_layered_filter_block kasvaa liikaa tai sisältää vanhentunutta faceted-haun välimuistia. Tämä ei poista tuotteita, kategorioita tai layered-hintaindeksiä. Puhdistuksen jälkeen PrestaShop tai hakumoduuli voi rakentaa välimuistin uudelleen tarvittaessa.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Koosta liikenteen lähdetilastot ennen poistoa';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Tallentaa päivittäiset koosteet liikenteen lähteistä ennen raakarivien poistamista.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Kun käytössä, moduuli tallentaa pienen päivittäisen koosteen ennen raakojen PrestaShop-tilastojen poistamista. Se säilyttää määrät kuten käynnit, sivunäytöt, lähdedomainin ja UTM-arvot. IP-osoitteita, täydellisiä referrer-URL-osoitteita tai user-agent-merkkijonoja ei tallenneta. Poista käytöstä, jos haluat vain poistaa etkä tarvitse historiakoosteita.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ce2b282d224153cccd645f28504ab4e2'] = 'Koostetilastojen säilytyspäivät';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_c3b4d14f7bff29c221039e891918f2dd'] = 'Kuinka kauan pientä päivittäistä koontitaulua säilytetään.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a97a6a6ab09f48206a543fdc7321bb60'] = 'Anna kuinka monta päivää liikenteen lähdekoosteet säilytetään moduulin taulussa. Esimerkki: 730 säilyttää noin kaksi vuotta päivittäisiä koosteita. Asetus vaikuttaa vain tauluun ps_jooim_dbcleaner_traffic_daily, ei PrestaShopin alkuperäisiin tilastotauluihin.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_4d4c70d739ad72835a8b62a81e07c611'] = 'Vanhentuneen lukon aikakatkaisu sekunteina';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Suojaus kahta samanaikaista puhdistusprosessia vastaan.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2c1824ea38ec688698a26f01a46e6b16'] = 'Anna sekuntien määrä, jonka jälkeen keskeneräinen puhdistuslukko katsotaan hylätyksi. Tämä suojaa tietokantaa kahdelta samanaikaiselta cron-ajolta. Suositeltu arvo: 7200. Laske vain, jos cron varmasti päättyy nopeasti.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_c9cc8cce247e49bae79f15173ce97354'] = 'Tallenna';
