$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Ota käyttöön vain, jos ps_layered_filter_block kasvaa liikaa tai sisältää vanhentunutta faceted-haun välimuistia. Tämä ei poista tuotteita, kategorioita tai layered-hintaindeksiä. Puhdistuksen jälkeen PrestaShop tai hakumoduuli voi rakentaa välimuistin uudelleen tarvittaessa.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_bf45506cce2494894a9df6ff4bdf83ae'] = 'Koosta liikenteen lähdetilastot ennen poistoa';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_d7e1a0c7e7973ebcde37aa659525105d'] = 'Tallentaa päivittäiset koosteet liikenteen lähteistä ennen raakarivien poistamista.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ae729759e10d7a626a8622321932a1f4'] = 'Kun käytössä, moduuli tallentaa pienen päivittäisen koosteen ennen raakojen PrestaShop-tilastojen poistamista. Se säilyttää määrät kuten käynnit, sivunäytöt, lähdedomainin ja UTM-arvot. IP-osoitteita, täydellisiä referrer-URL-osoitteita tai user-agent-merkkijonoja ei tallenneta. Poista käytöstä, jos haluat vain poistaa etkä tarvitse historiakoosteita.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ce2b282d224153cccd645f28504ab4e2'] = 'Koostetilastojen säilytyspäivät';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_c3b4d14f7bff29c221039e891918f2dd'] = 'Kuinka kauan pientä päivittäistä koontitaulua säilytetään.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a97a6a6ab09f48206a543fdc7321bb60'] = 'Anna kuinka monta päivää liikenteen lähdekoosteet säilytetään moduulin taulussa. Esimerkki: 730 säilyttää noin kaksi vuotta päivittäisiä koosteita. Asetus vaikuttaa vain tauluun ps_jooim_dbcleaner_traffic_daily, ei PrestaShopin alkuperäisiin tilastotauluihin.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_4d4c70d739ad72835a8b62a81e07c611'] = 'Vanhentuneen lukon aikakatkaisu sekunteina';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Suojaus kahta samanaikaista puhdistusprosessia vastaan.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_2c1824ea38ec688698a26f01a46e6b16'] = 'Anna sekuntien määrä, jonka jälkeen keskeneräinen puhdistuslukko katsotaan hylätyksi. Tämä suojaa tietokantaa kahdelta samanaikaiselta cron-ajolta. Suositeltu arvo: 7200. Laske vain, jos cron varmasti päättyy nopeasti.';
